javascript: (function() {
    var u = window.location.href,
        c = u.split('#')[0];
    try {
        var o = new URL(u);
        if (o.searchParams.has('uri')) {
            c = o.searchParams.get('uri')
        }
    } catch (e) {}
    var w = window.open('', '_blank');
    w.targetPdfUrl = c;
    w.document.open();
    var b64 = '';
    var html = new TextDecoder().decode(Uint8Array.from(atob(b64), function(c) {
        return c.charCodeAt(0);
    }));
    w.document.write(html);
    w.document.close();
})();